def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 7:
            for a in range(7, 3, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 4.5) / (a * b * 1.1 + 0.7)
                    priority += val * np.sin(ratio * b / (a + 2)) ** 2
            priority += np.exp(ratio - 7) * np.cos(ratio * 1.3) ** 1.7
            if bin_cap < item * 0.5:
                priority += np.log1p(item ** 3 / (bin_cap + 0.3)) * 7
            else:
                priority -= np.tanh(ratio - 7) * 4
        elif 4 < ratio <= 7:
            for c in range(2, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 4):
                    base = ((ratio - c) ** 2.8) * np.cos(ratio * d * 0.9) / (d + 0.3)
                    priority += np.tanh(base) * 1.5
            priority += np.log(ratio) * 8 - np.tanh(ratio - 4) * 3
            for e in range(1, 5):
                priority += np.sin(ratio * e * i) * np.exp(-0.1 * e)
        elif 2 <= ratio <= 4:
            s1 = 0
            for f in range(1, 15):
                s1 += ((ratio - 2) ** f) / (f * 1.5) * np.sin(f * ratio * 1.3)
            s2 = 0
            for g in range(1, 8):
                s2 += ((ratio - 2) ** g) / (g + 1) * np.cos(g * ratio * 2)
            priority = (s1 - s2) * np.cos(5 * ratio) + np.exp(-ratio / 3) * 4
            if bin_cap < item * 1.2:
                priority += np.sqrt(item / (bin_cap + 0.1)) * 3.5
            else:
                priority -= np.log1p(bin_cap) * 2
        elif 1 <= ratio < 2:
            s = 0
            for h in range(1, 12):
                s += ((2 - ratio) ** h) / (h ** 1.7 + 0.4) * np.sin(h * ratio * 3)
            penalty = 0
            if bin_cap < item * 0.9:
                penalty = np.exp(-bin_cap / (item + 0.1)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty + np.tanh(ratio * 1.5) * 2
            for j in range(1, 5):
                priority += np.cos(j * ratio * i * 0.9) * ((ratio - 1) ** j) / (j + 0.2)
        elif 0.5 <= ratio < 1:
            s = 0
            for k in range(1, 20):
                s += ((1 - ratio) ** k) / (k * 2.7) * np.cos(k * item * 1.3)
            priority = s
            if (i + int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for l in range(1, 7):
                priority += ((1 - ratio) ** l) * np.sin(l * item * 1.1) / (l + 0.5)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for m in range(1, 18):
                s += ((0.5 - ratio) ** m) / (m * 5) * np.sin(m * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.4) % 5 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for n in range(1, 8):
                priority += ((0.5 - ratio) ** n) / (n * 7) * np.cos(item * n * 1.3)
        else:
            s = 0
            for o in range(1, 14):
                s += ((0.2 - ratio) ** o) / (o * 6) * np.cos(o * item * 0.75)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.5) % 7 == 0:
                priority *= 3.7
            else:
                priority /= 3.7
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for p in range(1, 9):
                priority += ((0.2 - ratio) ** p) / (p * 8) * np.sin(item * p * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for q in range(1, 5):
            if (i + q) % 4 == 0:
                priority += np.sin(ratio * (i + q) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + q) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
